// Filtra eventos de Evolution API (MESSAGES_UPSERT)
// - Detecta comandos de administracion ("parar"/"seguir") escritos en el
//   grupo de escalamiento del equipo
// - Detecta respuestas manuales del equipo (mensajes propios directos a
//   un cliente) para que el bot no pierda el contexto de la conversacion
// - Separa audios de texto para el resto de los clientes
const body = $json.body ?? $json;
const data = body.data;

if (!data || !data.key) {
  return [];
}

const remoteJid = String(data.key.remoteJid);
const isGroup = remoteJid.endsWith('@g.us');
const msg = data.message || {};
const text = (msg.conversation || msg.extendedTextMessage?.text || '').trim();

if (data.key.fromMe) {
  if (isGroup) {
    // Mensajes propios del bot en el grupo (avisos, confirmaciones) - se ignoran
    return [];
  }
  // Alguien del equipo le escribio manualmente al cliente desde el telefono
  // conectado. Lo guardamos en el historial para que el bot no pierda el
  // contexto, aunque esta respuesta no la haya generado la IA.
  if (!text) return [];
  return [{
    json: {
      type: 'human_reply',
      sessionId: remoteJid,
      text,
      instance: body.instance,
      messageId: data.key.id
    }
  }];
}

if (isGroup) {
  const escalationGroup = 'TU_GRUPO_JID_AQUI@g.us';
  if (remoteJid === escalationGroup) {
    const normalized = text.trim().toLowerCase()
      .normalize('NFD').replace(/[\u0300-\u036f]/g, '') // saca tildes (pará -> para)
      .replace(/[!.,?¡¿]/g, '') // saca puntuacion en cualquier posicion
      .replace(/\s+/g, ' ')
      .trim();
    const m = normalized.match(/^(parar|para|frenar|frena|stop|seguir|segui|continuar|reanudar)(?:\s+(\d{6,15}))?$/);
    if (m) {
      const stopWords = ['parar', 'para', 'frenar', 'frena', 'stop'];
      const command = stopWords.includes(m[1]) ? 'paused' : 'active';
      const targetNumber = m[2] || null;
      return [{
        json: {
          type: 'admin_command',
          command,
          scope: targetNumber ? 'customer' : 'global',
          targetNumber,
          instance: body.instance,
          messageId: data.key.id
        }
      }];
    }
  }
  // Cualquier otro mensaje de grupo (o texto sin reconocer en el grupo del equipo) se ignora
  return [];
}

const isAudio = !!(msg.audioMessage || msg.pttMessage);
const isImage = !!(msg.imageMessage);
const caption = msg.imageMessage?.caption || '';
const finalText = text || caption.trim();

if (!isAudio && !isImage && !finalText) {
  return [];
}

// Meta marca el primer mensaje de una conversacion iniciada desde un
// anuncio de Facebook/Instagram (click-to-WhatsApp) con este campo
const isFromAd = !!(data.contextInfo && data.contextInfo.conversionSource);

return [{
  json: {
    type: 'customer_message',
    sessionId: remoteJid,
    number: remoteJid.split('@')[0],
    text: finalText,
    instance: body.instance,
    pushName: data.pushName || '',
    isAudio,
    isImage,
    isFromAd,
    messageId: data.key.id
  }
}];

// Deja pasar solo si el mensaje es un audio
if (!$json.isAudio) return [];
return [{ json: $json }];

// Deja pasar solo si el mensaje es texto (no audio, no imagen)
if ($json.isAudio || $json.isImage) return [];
return [{ json: $json }];

