// Extrae los mensajes y la decisión de escalar de la respuesta de Claude (formato JSON)
const resp = $json;
const ctx = $('Preparar mensajes (EDITA TU PROMPT AQUÍ)').first().json;

let replyParts = [];
let escalate = false;
let escalationReason = '';
let sendPaymentInfo = false;

if (resp.stop_reason === 'refusal') {
  replyParts = ['Disculpá, no puedo ayudarte con eso. ¿Tenés alguna consulta sobre el Combo Biotina?'];
  escalate = true;
  escalationReason = 'Respuesta bloqueada por seguridad (refusal)';
} else {
  const textBlock = (resp.content || []).find(b => b.type === 'text');
  const raw = textBlock ? textBlock.text : '';
  try {
    const parsed = JSON.parse(raw);
    replyParts = Array.isArray(parsed.reply_parts)
      ? parsed.reply_parts.map(p => String(p || '').trim()).filter(Boolean)
      : [];
    escalate = !!parsed.escalate;
    escalationReason = parsed.escalation_reason || '';
    sendPaymentInfo = !!parsed.send_payment_info;
    // Si algun reply_part es sospechosamente largo, no confiamos en el
    // contenido - mejor escalar en silencio que un cliente viendo basura
    if (replyParts.some(p => p.length > 500)) {
      throw new Error('reply_parts sospechosamente largo');
    }
  } catch (e) {
    // El JSON vino incompleto/corrupto (truncado por max_tokens, error del modelo, etc.)
    // NUNCA se debe mandar ese texto crudo al cliente - puede contener JSON roto,
    // razonamiento interno del modelo o basura repetida. Se escala en silencio
    // (sin mandarle nada al cliente) para que el equipo responda manual.
    replyParts = [];
    escalate = true;
    escalationReason = 'No se pudo interpretar la respuesta de la IA en el formato esperado';
  }
}

// Los datos de pago NUNCA los escribe la IA - son un texto fijo para evitar
// que se equivoque un caracter del alias/CVU al "recordarlos"
if (sendPaymentInfo) {
  const PAYMENT_INFO_TEXT = 'Alias: productoscapilarespg\nTitular: Agustín Jesús Gamarra\nCUIT/CUIL: 20-46648334-7\nCVU: 0000003100010473246731\n(Mercado Pago)';
  replyParts.push(PAYMENT_INFO_TEXT);
}

const reply = replyParts.join('\n');

return [{ json: { ...ctx, reply, replyParts, escalate, escalationReason } }];

// Genera filas para guardar en chat_history
const d = $json;
const rows = [{ json: { session_id: d.sessionId, role: 'user', content: d.text } }];
if (d.reply && d.reply.trim()) {
  rows.push({ json: { session_id: d.sessionId, role: 'assistant', content: d.reply } });
}
return rows;

// Deja pasar solo si Claude decidió que hay que escalar
if (!$json.escalate) return [];
return [{ json: $json }];

