const last10 = s => String(s || '').replace(/\D/g, '').slice(-10);
const sessionIdKey = d.scope === 'customer'
  ? ('__paused_customer__:' + last10(d.targetNumber))
  : '__bot_status__';
return [{ json: { ...d, sessionIdKey } }];

