const rows = $input.all().map(i => i.json).filter(r => r && r.session_id);
const ctx = $('Preparar lock').first().json;
const elapsedMs = Date.now() - ctx.lockStartedAt;

if (rows.length > 0) {
  return [{ json: { ...ctx, lockAcquired: true } }];
}
if (elapsedMs > 20000) {
  // No se pudo conseguir el lock a tiempo (otra conversacion del mismo cliente
  // sigue "trabada" hace rato). Seguimos igual para no perder el mensaje del
  // cliente, aceptando el riesgo raro de una carrera en este caso extremo.
  return [{ json: { ...ctx, lockAcquired: false, gaveUp: true } }];
}
return [{ json: { ...ctx, lockAcquired: false, retry: true } }];

const d = $('Es nuevo').first().json;
if (d.type !== 'human_reply') return [];
return [{ json: d }];

